DROP TABLE IF EXISTS `economic_indicators`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `economic_indicators` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `country_id` bigint(20) unsigned NOT NULL,
  `year` year(4) NOT NULL,
  `gdp` decimal(20,2) DEFAULT NULL,
  `inflation` decimal(8,2) DEFAULT NULL,
  `population` bigint(20) DEFAULT NULL,
  `exports` decimal(20,2) DEFAULT NULL,
  `imports` decimal(20,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `economic_country_year_unique` (`country_id`,`year`),
  CONSTRAINT `economic_indicators_country_id_foreign` FOREIGN KEY (`country_id`) REFERENCES `countries` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1076 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

