--
-- Table structure for table `risk_scores`
--

DROP TABLE IF EXISTS `risk_scores`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `risk_scores` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `country_id` bigint(20) unsigned NOT NULL,
  `weather_score` int(11) NOT NULL DEFAULT 0,
  `inflation_score` int(11) NOT NULL DEFAULT 0,
  `currency_score` int(11) NOT NULL DEFAULT 0,
  `news_score` int(11) NOT NULL DEFAULT 0,
  `port_score` int(11) NOT NULL DEFAULT 0,
  `total_score` int(11) NOT NULL DEFAULT 0,
  `risk_level` varchar(255) NOT NULL DEFAULT 'Low',
  `recommendation` text DEFAULT NULL,
  `score_date` date DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `risk_score_country_unique` (`country_id`),
  KEY `risk_level_score_index` (`risk_level`,`total_score`),
  CONSTRAINT `risk_scores_country_id_foreign` FOREIGN KEY (`country_id`) REFERENCES `countries` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=501 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

